import java.util.Scanner;

public class SecureBufferOverflow {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Allocate a buffer with dynamic size based on input length
        byte[] buffer = new byte[input.length()];

        // Perform bounds checking to avoid overflow
        int copyLength = Math.min(input.length(), buffer.length);

        // Copy input bytes into the buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, copyLength);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
